mapper.select:
SELECT r.*
FROM order_refund r
INNER JOIN `order` o ON r.order_id = o.id
WHERE o.member_id = #{memberId}
AND r.created_at >= #{createdAt}
ORDER BY r.created_at DESC

mapper.insert:
INSERT INTO order_refund (
    order_id, refund_no, payment_id, amount, reason, status, refund_time, third_party_refund_no, created_at, updated_at
) VALUES (
    #{orderId}, #{refundNo}, #{paymentId}, #{amount}, #{reason}, #{status}, #{refundTime}, #{thirdPartyRefundNo}, #{createdAt}, #{updatedAt}
)
